from flask import Flask, request, jsonify
import logging
from werkzeug.security import check_password_hash

app = Flask(__name__)

# Configure logging
logging.basicConfig(filename='application.log', level=logging.INFO)

# Dummy user database for demonstration purposes
users = {
    'user1': {'password_hash': 'pbkdf2:sha256:150000$...', 'email': 'user1@example.com'}
}

@app.route('/login', methods=['POST'])
def login():
    data = request.get_json()
    
    # Validate input
    if not all(key in data for key in ['username', 'password']):
        return jsonify({'error': 'Missing username or password'}), 400
    
    username = data['username']
    password = data['password']
    
    # Check user credentials
    if username in users and check_password_hash(users[username]['password_hash'], password):
        # Log successful login attempt
        log_login_attempt(username, request.remote_addr, request.headers.get('User-Agent'))
        return jsonify({'message': 'Login successful'}), 200
    else:
        # Log failed login attempt
        log_login_attempt(username, request.remote_addr, request.headers.get('User-Agent'), success=False)
        return jsonify({'error': 'Invalid credentials'}), 401

def log_login_attempt(username, ip_address, user_agent, success=True):
    if success:
        logging.info(f'Successful login attempt: Username={username}, IP Address={ip_address}, User Agent={user_agent}')
    else:
        logging.warning(f'Failed login attempt: Username={username}, IP Address={ip_address}, User Agent={user_agent}')

if __name__ == '__main__':
    app.run(debug=True)